var refreshToken = async (refreshToken3) => {
  const verifiedToken = jwtUtils.verifyToken(refreshToken3, config_default.jwtRefreshSecret);
  if (!verifiedToken.success) {
    throw new Error("Invalid refresh token");
  }
  const { id } = verifiedToken.data;
  const user = await prisma.user.findUniqueOrThrow({
    where: {
      id
    }
  });
  if (user.status === "INACTIVE") {
    throw new Error("User is inactive");
  }
  ;
  const jwtPayload = {
    id: user.id,
    name: user.name,
    email: user.email,
    role: user.role
  };
  const accessToken = jwtUtils.createToken(
    jwtPayload,
    config_default.jwtSecret,
    config_default.jwtExpiration
  );
  return { accessToken };
};
