var createService = async (technicianId, payload) => {
  const category = await prisma.category.findUnique({
    where: {
      id: payload.categoryId
    }
  });
  if (!category) {
    throw new Error("Category not found");
  }
  const result = await prisma.service.create({
    data: {
      title: payload.title,
      description: payload.description,
      price: payload.price,
      location: payload.location,
      categoryId: payload.categoryId,
      technicianId
    },
    include: {
      category: true,
      technician: true
    }
  });
  return result;
};
var getAllServices = async (query) => {
  const {
    search,
    categoryId,
    location,
    minPrice,
    maxPrice,
    page = "1",
    limit = "10",
    sortBy = "createdAt",
    sortOrder = "desc"
  } = query;
  const where = {};
  if (search) {
    where.title = {
      contains: search,
      mode: "insensitive"
    };
  }
  if (categoryId) {
    where.categoryId = categoryId;
  }
  if (location) {
    where.location = {
      contains: location,
      mode: "insensitive"
    };
  }
  if (minPrice || maxPrice) {
    where.price = {};
    if (minPrice) {
      where.price.gte = Number(minPrice);
    }
    if (maxPrice) {
      where.price.lte = Number(maxPrice);
    }
  }
  const skip = (Number(page) - 1) * Number(limit);
  const services = await prisma.service.findMany({
    where,
    include: {
      category: true,
      technician: {
        omit: {
          password: true
        }
      }
    },
    skip,
    take: Number(limit),
    orderBy: {
      [sortBy]: sortOrder
    }
  });
  const total = await prisma.service.count({
    where
  });
  return {
    meta: {
      page: Number(page),
      limit: Number(limit),
      total
    },
    data: services
  };
};
